# scripts/generate_weekly_digest.py
# Run via cron: 0 8 * * 1  (every Monday at 08:00)
import json
from datetime import date, timedelta
from pathlib import Path
import smtplib
from email.mime.text import MIMEText

def load_scorecard(path: str) -> dict:
    return json.loads(Path(path).read_text())

def rag_emoji(status: str) -> str:
    return {"green": "🟢", "amber": "🟡", "red": "🔴"}.get(status, "⚪")

def format_digest(current: dict, previous: dict) -> str:
    lines = [
        f"## GenAI Service Weekly Scorecard — Week of {date.today()}",
        "",
        "### Metrics",
        "| Dimension | Metric | Current | Last Week | Status |",
        "|-----------|--------|---------|-----------|--------|",
    ]

    for dimension, metrics in current["dimensions"].items():
        for metric_name, data in metrics.items():
            current_val = data["value"]
            prev_val = previous["dimensions"].get(dimension, {}).get(metric_name, {}).get("value", "N/A")
            status = rag_emoji(data["rag"])
            lines.append(f"| {dimension} | {metric_name} | {current_val} | {prev_val} | {status} |")

    # Amber/Red details
    issues = [
        (d, m, data)
        for d, metrics in current["dimensions"].items()
        for m, data in metrics.items()
        if data["rag"] in ("amber", "red")
    ]

    if issues:
        lines += ["", "### Issues Requiring Action"]
        for dimension, metric, data in issues:
            lines += [
                f"**{rag_emoji(data['rag'])} {metric}**: {data['value']} (threshold: {data['threshold']})",
                f"  - Cause: {data.get('cause', 'Under investigation')}",
                f"  - Owner: {data.get('owner', 'Unassigned')}",
                f"  - Action: {data.get('action', 'TBD')}",
                "",
            ]

    # Open action items
    open_tickets = json.loads(Path("scorecard-actions.json").read_text())
    due_this_week = [t for t in open_tickets if t["due"] <= str(date.today() + timedelta(days=7))]

    if due_this_week:
        lines += ["### Actions Due This Week"]
        for ticket in due_this_week:
            lines.append(f"- #{ticket['id']}: {ticket['title']} (due {ticket['due']}, @{ticket['owner']})")

    return "\n".join(lines)


if __name__ == "__main__":
    current = load_scorecard("scorecard-latest.json")
    previous = load_scorecard("scorecard-previous.json")
    digest = format_digest(current, previous)

    # Post to Slack
    import requests
    requests.post(
        "https://hooks.slack.com/services/PLACEHOLDER",
        json={"text": digest, "mrkdwn": True}
    )
    print("Weekly digest posted to Slack")
